import java.io.*;

public class SecureCommandExecutionDemo {

    public static void main(String[] args) {
        try {
            BufferedReader reader = new BufferedReader(new InputStreamReader(System.in));

            System.out.print("Enter a command to execute: ");
            String command = reader.readLine();

            // Validate the command input to ensure it contains only allowed characters
            if (!command.matches("[a-zA-Z0-9]+")) {
                throw new IllegalArgumentException("Invalid command format");
            }

            // Execute the command using ProcessBuilder with proper handling
            ProcessBuilder processBuilder = new ProcessBuilder("ls", command);
            processBuilder.redirectErrorStream(true); // Redirect error stream to input stream

            Process process = processBuilder.start();

            BufferedReader inputReader = new BufferedReader(new InputStreamReader(process.getInputStream()));
            String line;
            while ((line = inputReader.readLine()) != null) {
                System.out.println(line);
            }

        } catch (IOException | IllegalArgumentException e) {
            e.printStackTrace();
        }
    }
}

